import { mkdirSync, writeFileSync, readFileSync } from 'node:fs'
import { dirname, join } from 'node:path'

const bundle = JSON.parse(readFileSync(join(process.cwd(), 'src', 'data', 'vrmsProductionData.json'), 'utf8'))
const outputPath = join(process.cwd(), 'supabase', 'seed.vrms.generated.sql')

function sql(value) {
  if (value === null || value === undefined || value === '') return 'null'
  return `'${String(value).replaceAll("'", "''")}'`
}

function jsonb(value) {
  return `${sql(JSON.stringify(value))}::jsonb`
}

const lines = [
  '-- Generated by npm run supabase:seed:vrms',
  '-- Review before applying to a non-local Supabase project.',
  'begin;',
  '',
]

for (const profile of bundle.profiles) {
  lines.push(
    `insert into public.profiles (id, email, display_name, role, active) values (${sql(profile.id)}, ${sql(profile.email)}, ${sql(profile.displayName)}, ${sql(profile.role)}, true) on conflict (id) do update set email = excluded.email, display_name = excluded.display_name, role = excluded.role, active = excluded.active;`,
  )
}

lines.push('')

for (const row of bundle.registryValues) {
  lines.push(
    `insert into public.registry_values (id, registry_type, value) values (${sql(row.id)}, ${sql(row.registryType)}, ${sql(row.value)}) on conflict (registry_type, value) do update set value = excluded.value;`,
  )
}

lines.push('')

for (const doc of bundle.routingDocuments) {
  lines.push(
    `insert into public.routing_documents (routing_tracker, doc_tracer, equipment_product, category, il_tag, status, sent_routing_to, email, date_sent, report_protocol, batch_no, client_name, department, prepared_by, date_prepared, checked_by, date_checked, target_completion_date, remarks, signatories, total_routing_duration, routing_completed_at, created_at, updated_at, updated_by) values (${sql(doc.routingTracker)}, ${sql(doc.docTracer)}, ${sql(doc.equipmentProduct)}, ${sql(doc.category)}, ${sql(doc.ilTag)}, ${sql(doc.status)}, ${sql(doc.sentRoutingTo)}, ${sql(doc.email)}, ${sql(doc.dateSent)}, ${sql(doc.reportProtocol)}, ${sql(doc.batchNo)}, ${sql(doc.clientName)}, ${sql(doc.department)}, ${sql(doc.preparedBy)}, ${sql(doc.datePrepared)}, ${sql(doc.checkedBy)}, ${sql(doc.dateChecked)}, ${sql(doc.targetCompletionDate)}, ${sql(doc.remarks)}, ${jsonb(doc.signatories)}, ${sql(doc.totalRoutingDuration)}, ${sql(doc.routingCompletedAt)}, ${sql(doc.createdAt)}, ${sql(doc.updatedAt)}, ${sql(doc.updatedBy)}) on conflict (routing_tracker) do update set doc_tracer = excluded.doc_tracer, equipment_product = excluded.equipment_product, category = excluded.category, il_tag = excluded.il_tag, status = excluded.status, sent_routing_to = excluded.sent_routing_to, email = excluded.email, date_sent = excluded.date_sent, report_protocol = excluded.report_protocol, batch_no = excluded.batch_no, client_name = excluded.client_name, department = excluded.department, prepared_by = excluded.prepared_by, date_prepared = excluded.date_prepared, checked_by = excluded.checked_by, date_checked = excluded.date_checked, target_completion_date = excluded.target_completion_date, remarks = excluded.remarks, signatories = excluded.signatories, total_routing_duration = excluded.total_routing_duration, routing_completed_at = excluded.routing_completed_at, created_at = excluded.created_at, updated_at = excluded.updated_at, updated_by = excluded.updated_by;`,
  )
}

lines.push('')

for (const event of bundle.auditEvents) {
  lines.push(
    `insert into public.audit_events (id, event_timestamp, user_email, action, routing_tracker, doc_tracer, details) values (${sql(event.id)}, ${sql(event.timestamp)}, ${sql(event.userEmail)}, ${sql(event.action)}, ${sql(event.routingTracker)}, ${sql(event.docTracer)}, ${sql(event.details)}) on conflict (id) do nothing;`,
  )
}

lines.push('', 'commit;', '')

mkdirSync(dirname(outputPath), { recursive: true })
writeFileSync(outputPath, lines.join('\n'))
console.log(`Generated ${outputPath}`)
